27	/*
28	 * This function accepts an nD NumPy array of size (..., n, n) and, if possible,
29	 * computes the matrix square root for each (n, n) slice. The input must be at
30	 * least 2-dimensional.
31	 *
32	 * Real valued input has the possibility of resulting in a complex-valued result
33	 * and this is tracked internally and hence depending on the resulting flag the
34	 * caller should view the resulting single/double (n, 2n) array as (n, n)
35	 * single/double complex array.
36	 *
37	 * This function tests for the dtypes to be LAPACK compatible and for squareness.
38	 *
39	 * IMPORTANT: This function does not test for 0-dimensional, or nD arrays where
40	 * some dimensions are 0. It is expected to have this case caught by the caller.
41	*/
42	static PyObject*
43	recursive_schur_sqrtm(PyObject* Py_UNUSED(dummy), PyObject *args) {
44	    int isComplex = 0, isIllconditioned = 0, isSingular = 0;
45	    CBLAS_INT info = 0;
46	    PyArrayObject *ap_Am = NULL;
47	    void* mem_ret = NULL;
48	    PyArrayObject* ap_ret = NULL;
49	
50	    // Get the input array
51	    if (!PyArg_ParseTuple(args, ("O!"), &PyArray_Type, (PyObject **)&ap_Am))
52	    {
53	        return NULL;
54	    }
55	
56	    // Check for dtype compatibility
57	    if ((PyArray_TYPE(ap_Am) != NPY_FLOAT64) &&
58	         (PyArray_TYPE(ap_Am) != NPY_FLOAT32) &&
59	         (PyArray_TYPE(ap_Am) != NPY_COMPLEX64) &&
60	         (PyArray_TYPE(ap_Am) != NPY_COMPLEX128)
61	       )
62	    {
63	        PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Input must be an nD-array"
64	                          "  of type float32, float64, complex64, or complex128.");
65	    }
66	
67	    int ndim = PyArray_NDIM(ap_Am);              // Number of dimensions
68	    npy_intp* shape = PyArray_SHAPE(ap_Am);      // Array shape
69	    npy_intp n = shape[ndim - 1];                // Slice size
70	    int input_type = PyArray_TYPE(ap_Am);        // Data type enum value
71	    // Compare last two dimensions for squareness
72	    if (n != shape[ndim - 2])
73	    {
74	        PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Last two dimensions of the input must be the same.");
75	    }
76	
77	    // Create the output array with the same shape as the input with twice the
78	    // number of entries to accommodate for potential complex-valued data from
79	    // real data which will be cast to complex e.g., "ret.asview(complex128)"
80	    // Example, (3, 3) -> (18), (4, 5, 5) -> (4, 50)
81	    npy_intp ret_dims = 1;
82	    for (int i = 0; i < ndim; i++) { ret_dims *= shape[i]; }
83	    if ((input_type == NPY_FLOAT32) || (input_type == NPY_FLOAT64))
84	    {
85	        ret_dims *= 2;
86	    }
87	
88	    if (PyArray_TYPE(ap_Am) == NPY_FLOAT32)
89	    {
90	        mem_ret = malloc(ret_dims*sizeof(float));
91	        if (mem_ret == NULL) { PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Memory allocation failed."); }
92	        matrix_squareroot_s(ap_Am, (float*)mem_ret, &isIllconditioned, &isSingular, &info, &isComplex);
93	
94	    } else if (PyArray_TYPE(ap_Am) == NPY_FLOAT64) {
95	
96	        mem_ret = malloc(ret_dims*sizeof(double));
97	        if (mem_ret == NULL) { PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Memory allocation failed."); }
98	        matrix_squareroot_d(ap_Am, (double*)mem_ret, &isIllconditioned, &isSingular, &info, &isComplex);
99	
100	    } else if (PyArray_TYPE(ap_Am) == NPY_COMPLEX64) {
101	
102	        mem_ret = malloc(ret_dims*sizeof(SCIPY_C));
103	        if (mem_ret == NULL) { PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Memory allocation failed."); }
104	        matrix_squareroot_c(ap_Am, (SCIPY_C*)mem_ret, &isIllconditioned, &isSingular, &info, &isComplex);
105	        isComplex = 1;
106	
107	    } else if (PyArray_TYPE(ap_Am) == NPY_COMPLEX128) {
108	
109	        mem_ret = malloc(ret_dims*sizeof(SCIPY_Z));
110	        if (mem_ret == NULL) { PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Memory allocation failed."); }
111	        matrix_squareroot_z(ap_Am, (SCIPY_Z*)mem_ret, &isIllconditioned, &isSingular, &info, &isComplex);
112	        isComplex = 1;
113	
114	    } else {
115	        PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Unsupported input data type to C function.");
116	    }
117	
118	    if (info < 0)
119	    {
120	        // Internal failure memory or LAPACK error, fail and return the error code in info
121	        free(mem_ret);
122	        Py_INCREF(Py_None);
123	        return Py_BuildValue(
124	            "Niin", Py_None, isIllconditioned,
125	            isSingular, (Py_ssize_t)info
126	        );
127	    }
128	
129	    if (!isComplex)
130	    {
131	        // Input and output is real, truncate the extra space at the end
132	        npy_intp new_size = (ret_dims/2)*(input_type == NPY_FLOAT32 ? sizeof(float) : sizeof(double));
133	        void* new_ret = realloc(mem_ret, new_size);
134	        // Quite unlikely but still allowed to fail
135	        if (!new_ret) {
136	            free(mem_ret);
137	            PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Memory reallocation failed.");
138	        }
139	        mem_ret = new_ret;
140	        ap_ret = (PyArrayObject*)PyArray_SimpleNewFromData(ndim, shape, input_type, mem_ret);
141	        if (ap_ret == NULL) {
142	            free(mem_ret);
143	            PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Failed to create numpy array from data.");
144	        }
145	    } else if ((input_type == NPY_FLOAT32) || (input_type == NPY_FLOAT64)) {
146	        // Input was real, result is complex, then view the result as complex
147	        int new_type = (PyArray_TYPE(ap_Am) == NPY_FLOAT32 ? NPY_COMPLEX64 : NPY_COMPLEX128);
148	        ap_ret = (PyArrayObject*)PyArray_SimpleNewFromData(ndim, shape, new_type, mem_ret);
149	        if (ap_ret == NULL) {
150	            free(mem_ret);
151	            PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Failed to create numpy array from data.");
152	        }
153	    } else {
154	        // Input was complex, result is complex, only reshape
155	        ap_ret = (PyArrayObject*)PyArray_SimpleNewFromData(ndim, shape, PyArray_TYPE(ap_Am), mem_ret);
156	        if (ap_ret == NULL) {
157	            free(mem_ret);
158	            PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Failed to create numpy array from data.");
159	        }
160	    }
161	
162	    // Attach the buffer to a capsule
163	    PyObject* capsule = PyCapsule_New(mem_ret, NULL, capsule_destructor);
164	    if (capsule == NULL) {
165	        Py_DECREF(ap_ret);
166	        free(mem_ret);
167	        PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Failed to create capsule.");
168	    }
169	    // For ref counting of the memory
170	    if (PyArray_SetBaseObject(ap_ret, capsule) == -1) {
171	        Py_DECREF(ap_ret);
172	        Py_DECREF(capsule);
173	        PYERR(matfuncs_error, "scipy.linalg._matfuncs:sqrtm: Failed to set array's base.");
174	    }
175	
176	    // Return the result
177	    return Py_BuildValue(
178	        "Niin", PyArray_Return(ap_ret), isIllconditioned,
179	        isSingular, (Py_ssize_t)info
180	    );
181	}
