{
    // U, V computation.
    // We utilize the unused powers of Am as scratch memory depending on m value.
    // Final U is stored Am[3], final V is stored Am[1] for all m.
    // b[m] = 1.0 for all m.

    CBLAS_INT int1 = 1, n = (CBLAS_INT)size_n;
